import React from "react";
import { useState } from "react";
import "./nav.css";

let myRef = React.createRef();
export default function Nav() {
  const [Active, IsActive] = React.useState(false);
  const handleClick = () => {
    if (IsActive != true) {
      IsActive(true);
      console.log(Active);
    } else {
      IsActive(false);
      console.log(Active);
    }
  };

  function handleTextareaChange() {}

  return (
    <div>
      <div
        value={Active}
        className="pushMenu"
        onChange={handleTextareaChange}
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

